import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import FacultyLayout from "../../layouts/FacultyLayout";

function FacultyDashboard() {

  const navigate = useNavigate();

  const { user } = useAuth();

  const submittedQuarters = [];
  const draftQuarters = [];

  ["Q1", "Q2", "Q3", "Q4"].forEach(
    (quarter) => {

      const draft =
        localStorage.getItem(
          `facultyDraft_${quarter}`
        );

      const submitted =
        localStorage.getItem(
          `facultySubmission_${quarter}`
        );

      if (submitted) {

        submittedQuarters.push(
          quarter
        );

      } else if (draft) {

        draftQuarters.push(
          quarter
        );

      }

    }
  );

  const notStartedQuarters =
    ["Q1", "Q2", "Q3", "Q4"].filter(
      (quarter) =>
        !submittedQuarters.includes(
          quarter
        ) &&
        !draftQuarters.includes(
          quarter
        )
    );

  return (

    <FacultyLayout>

      {/* Welcome Banner */}

      <div
        style={{
          background:
            "linear-gradient(135deg,#2563eb,#1e40af)",
          color: "white",
          padding: "30px",
          borderRadius: "15px",
          marginBottom: "30px"
        }}
      >

        <h1
          style={{
            margin: 0
          }}
        >
          Welcome,
          {" "}
          {user?.name}
        </h1>

        <p
          style={{
            marginTop: "10px",
            opacity: 0.9
          }}
        >
          SRIHER IQAC Faculty Dashboard
        </p>

      </div>

      {/* Statistics */}

      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(auto-fit,minmax(250px,1fr))",
          gap: "20px",
          marginBottom: "40px"
        }}
      >

        <div className="stat-card">

          <h2>
            {submittedQuarters.length}
          </h2>

          <p>
            Submitted Quarters
          </p>

        </div>

        <div className="stat-card">

          <h2>
            {draftQuarters.length}
          </h2>

          <p>
            Draft Reports
          </p>

        </div>

        <div className="stat-card">

          <h2>
            {notStartedQuarters.length}
          </h2>

          <p>
            Not Started
          </p>

        </div>

      </div>

      {/* Quarter Status */}

      <h2
        style={{
          marginBottom: "20px"
        }}
      >
        Quarter Status
      </h2>

      <div
        className="status-card"
      >

        <div
          className="status-row"
        >
          <span>
            Submitted
          </span>

          <strong
            style={{
              color:
                "#16a34a"
            }}
          >
            {
              submittedQuarters.length
                ? submittedQuarters.join(
                    ", "
                  )
                : "None"
            }
          </strong>
        </div>

        <div
          className="status-row"
        >
          <span>
            Draft
          </span>

          <strong
            style={{
              color:
                "#f59e0b"
            }}
          >
            {
              draftQuarters.length
                ? draftQuarters.join(
                    ", "
                  )
                : "None"
            }
          </strong>
        </div>

        <div
          className="status-row"
        >
          <span>
            Not Started
          </span>

          <strong
            style={{
              color:
                "#ef4444"
            }}
          >
            {
              notStartedQuarters.join(
                ", "
              )
            }
          </strong>
        </div>

      </div>

      {/* Quick Actions */}

      <h2
        style={{
          marginTop: "40px",
          marginBottom: "20px"
        }}
      >
        Quick Actions
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(auto-fit,minmax(280px,1fr))",
          gap: "20px"
        }}
      >

        <div className="action-card">

          <h3>
            📝 Questionnaire
          </h3>

          <p>
            Fill quarterly IQAC questionnaire
          </p>

          <button
            onClick={() =>
              navigate(
                "/faculty/questionnaire"
              )
            }
          >
            Open
          </button>

        </div>

        <div className="action-card">

          <h3>
            📂 My Submissions
          </h3>

          <p>
            View all submitted reports
          </p>

          <button
            onClick={() =>
              navigate(
                "/faculty/submissions"
              )
            }
          >
            View
          </button>

        </div>

        <div className="action-card">

          <h3>
            👤 Profile
          </h3>

          <p>
            Update your profile details
          </p>

          <button
            onClick={() =>
              navigate(
                "/profile"
              )
            }
          >
            Open
          </button>

        </div>

      </div>

      <style>

        {`

        .stat-card{

          background:white;
          padding:25px;
          border-radius:15px;
          box-shadow:0 4px 15px rgba(0,0,0,0.08);
          text-align:center;

        }

        .stat-card h2{

          color:#2563eb;
          margin:0;
          font-size:32px;

        }

        .status-card{

          background:white;
          padding:25px;
          border-radius:15px;
          box-shadow:0 4px 15px rgba(0,0,0,0.08);

        }

        .status-row{

          display:flex;
          justify-content:space-between;
          padding:12px 0;
          border-bottom:1px solid #e5e7eb;

        }

        .status-row:last-child{

          border-bottom:none;

        }

        .action-card{

          background:white;
          padding:25px;
          border-radius:15px;
          box-shadow:0 4px 15px rgba(0,0,0,0.08);

        }

        .action-card button{

          margin-top:10px;
          background:#2563eb;
          color:white;
          border:none;
          padding:10px 20px;
          border-radius:8px;
          cursor:pointer;

        }

        .action-card button:hover{

          background:#1d4ed8;

        }

        `}

      </style>

    </FacultyLayout>

  );
}

export default FacultyDashboard;
